# Auto-generated Elementary Cellular Automaton rule implementations
# Generated by eca_dp.jl
#
# Each rule operates on a packed bit array x of type T with N active bits,
# using periodic (circular) boundary conditions via shift_left / shift_right.
#   l = shift_left(x)  — left neighbours  (cell i-1 for each cell i)
#   c = x              — centre cells
#   r = shift_right(x) — right neighbours (cell i+1 for each cell i)

struct ECARule{R, N} end
ECARule(rule::Int, nbits::Int) = ECARule{rule, nbits}()

@inline function shift_left(x::T, ::Val{N}) where {T, N}
    (x << 1) | (x >> (N - 1))
end

@inline function shift_right(x::T, ::Val{N}) where {T, N}
    (x >> 1) | ((x & one(T)) << (N - 1))
end

